// JWT Token Validation - v2.0.0
// v2.0.0: Fetch JWT_SECRET from app_config
const webhookData = $('PUT Update Destination - Webhook').first().json;
const jwtSecret = $('Get JWT Secret - Supabase').first().json.value;

if (!jwtSecret) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'JWT secret not configured',
      statusCode: 500,
      timestamp: new Date().toISOString()
    }
  }];
}

const authHeader = webhookData.headers?.authorization || webhookData.headers?.Authorization;

if (!authHeader) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Missing authorization header',
      statusCode: 401,
      timestamp: new Date().toISOString()
    }
  }];
}

if (!authHeader.startsWith('Bearer ')) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Invalid authorization format',
      statusCode: 401,
      timestamp: new Date().toISOString()
    }
  }];
}

const token = authHeader.substring(7);

function simpleHash(input) {
  let hash = 0;
  for (let i = 0; i < input.length; i++) {
    const char = input.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return hash.toString(36);
}

function verifyJWT(token, secret) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) {
      return { valid: false, error: 'Invalid token format' };
    }
    const [header, payload, sig] = parts;
    const expected = simpleHash(`${header}.${payload}.${secret}`);
    if (sig !== expected) {
      return { valid: false, error: 'Invalid token signature' };
    }
    const decoded = JSON.parse(atob(payload));
    const now = Math.floor(Date.now() / 1000);
    if (decoded.exp && decoded.exp < now) {
      return { valid: false, error: 'Token expired' };
    }
    return { valid: true, payload: decoded };
  } catch (e) {
    return { valid: false, error: 'Token verification failed' };
  }
}

const result = verifyJWT(token, jwtSecret);

if (!result.valid) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: result.error || 'Invalid token',
      statusCode: 401,
      timestamp: new Date().toISOString()
    }
  }];
}

const p = result.payload;

if (p.type === 'limited') {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Full authentication required',
      statusCode: 403,
      timestamp: new Date().toISOString()
    }
  }];
}

if (p.type === 'refresh') {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Refresh tokens cannot be used here',
      statusCode: 403,
      timestamp: new Date().toISOString()
    }
  }];
}

const allowedRoles = ['admin', 'supervisor'];
if (!allowedRoles.includes(p.role)) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Insufficient permissions',
      statusCode: 403,
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    _route: 'authorized',
    authenticated: true,
    user: {
      id: p.user_id || null,
      username: p.sub,
      role: p.role,
      tokenType: p.type
    },
    requestBody: webhookData.body,
    timestamp: new Date().toISOString()
  }
}];
// v2.0.0 - Dynamic JWT secret + RBAC

// Validate Update Data - v1.0.0
// Validates incoming update data, builds updateFields object
const data = $json.requestBody || {};
const user = $('JWT Validation - Code').first().json.user;
const errors = [];

// id is required for update
if (!data.id && data.id !== 0) {
  errors.push('Destination id is required');
}

const destinationId = parseInt(data.id);
if (isNaN(destinationId) || destinationId <= 0) {
  errors.push('Destination id must be a positive integer');
}

// Email format validation (if provided)
if (data.email !== undefined && data.email !== null && data.email !== '') {
  if (!data.email.includes('@')) {
    errors.push('Invalid email format');
  }
}

// Contacts JSONB validation (if provided)
let parsedContacts = undefined;
if (data.contacts !== undefined) {
  if (data.contacts === null) {
    parsedContacts = [];
  } else if (typeof data.contacts === 'string') {
    try {
      parsedContacts = JSON.parse(data.contacts);
    } catch (e) {
      errors.push('Contacts must be valid JSON');
    }
  } else {
    parsedContacts = data.contacts;
  }
  if (parsedContacts !== undefined && !Array.isArray(parsedContacts)) {
    errors.push('Contacts must be an array');
  }
}

if (errors.length > 0) {
  return [{
    json: {
      success: 'false',
      errors: errors,
      message: 'Validation failed: ' + errors.join(', '),
      skipSupabase: true
    }
  }];
}

// Build update object with only provided fields
const updateFields = {};

if (data.name !== undefined) {
  updateFields.name = data.name ? data.name.trim() : '';
}
if (data.address !== undefined) {
  updateFields.address = data.address ? data.address.trim() : '';
}
if (data.city !== undefined) {
  updateFields.city = data.city ? data.city.trim() : '';
}
if (data.province !== undefined) {
  updateFields.province = data.province ? data.province.trim().toUpperCase() : '';
}
if (data.postal_code !== undefined) {
  updateFields.postal_code = data.postal_code ? data.postal_code.trim().toUpperCase() : '';
}
if (data.phone !== undefined) {
  updateFields.phone = data.phone ? data.phone.trim() : null;
}
if (data.email !== undefined) {
  updateFields.email = data.email ? data.email.trim().toLowerCase() : null;
}
if (parsedContacts !== undefined) {
  updateFields.contacts = parsedContacts;
}
if (data.notes !== undefined) {
  updateFields.notes = data.notes ? data.notes.trim() : null;
}
if (data.active !== undefined) {
  updateFields.active = data.active;
}

// Auto-extract first contact's phone/email if contacts updated
if (parsedContacts !== undefined && parsedContacts.length > 0) {
  if (updateFields.phone === undefined && parsedContacts[0].phone) {
    updateFields.phone = parsedContacts[0].phone.trim();
  }
  if (updateFields.email === undefined && parsedContacts[0].email) {
    updateFields.email = parsedContacts[0].email.trim().toLowerCase();
  }
}

updateFields.updated_at = new Date().toISOString();

const fieldCount = Object.keys(updateFields).length;
if (fieldCount <= 1) {
  return [{
    json: {
      success: 'false',
      errors: ['No fields provided to update'],
      message: 'No fields provided to update',
      skipSupabase: true
    }
  }];
}

return [{
  json: {
    success: 'true',
    destinationId: destinationId,
    updateFields: updateFields,
    userId: user?.id || null,
    userName: user?.username || 'unknown',
    userRole: user?.role || 'unknown'
  }
}];
// v1.0.0 - Validate update data with user context

// Detect Changes - v1.0.0
// Compares old destination with update fields to detect address/name changes
const validData = $('Validate Update Data - Code').first().json;
const existingDest = $input.first().json;

if (!existingDest || !existingDest.id) {
  return [{
    json: {
      success: 'false',
      notFound: 'true',
      message: 'Destination not found'
    }
  }];
}

const uf = validData.updateFields;

// Detect address change (any of address, city, province, postal_code)
const addressFields = ['address', 'city', 'province', 'postal_code'];
let addressChanged = false;
addressFields.forEach(f => {
  if (uf[f] !== undefined) {
    const oldVal = (existingDest[f] || '').toString().trim().toLowerCase();
    const newVal = (uf[f] || '').toString().trim().toLowerCase();
    if (oldVal !== newVal) addressChanged = true;
  }
});

// Detect name change
const oldName = (existingDest.name || '').trim();
const newName = uf.name !== undefined ? (uf.name || '').trim() : oldName;
const nameChanged = oldName !== newName;

// Detect deactivation
const isBeingDeactivated = uf.active === false && existingDest.active === true;
const willBeActive = uf.active !== undefined ? uf.active : existingDest.active;

// Build full destination address (post-update)
const finalAddress = uf.address !== undefined ? uf.address : existingDest.address;
const finalCity = uf.city !== undefined ? uf.city : existingDest.city;
const finalProvince = uf.province !== undefined ? uf.province : existingDest.province;
const finalPostalCode = uf.postal_code !== undefined ? uf.postal_code : existingDest.postal_code;
const destAddress = [finalAddress, finalCity, finalProvince, finalPostalCode].filter(Boolean).join(', ');

return [{
  json: {
    success: 'true',
    destinationId: validData.destinationId,
    updateFields: uf,
    existingDest: existingDest,
    oldName: oldName,
    newName: newName,
    nameChanged: nameChanged ? 'true' : 'false',
    addressChanged: addressChanged ? 'true' : 'false',
    isBeingDeactivated: isBeingDeactivated ? 'true' : 'false',
    willBeActive: willBeActive ? 'true' : 'false',
    destAddress: destAddress,
    destLabel: newName + ' (' + destAddress + ')',
    needsAsync: (addressChanged && !isBeingDeactivated && willBeActive) ? 'true' : 'false',
    needsNameRename: nameChanged ? 'true' : 'false',
    userId: validData.userId,
    userName: validData.userName,
    userRole: validData.userRole
  }
}];
// v1.0.0 - Detect address/name changes for async branching

// Prepare Tasks and Branches - v1.0.0
// Prepares data for async distance + travel time recalculation
const mergedInput = $input.all().map(item => item.json);
const detectData = $('Detect Changes - Code').first().json;

const clients = mergedInput.filter(item =>
  item.knumber !== undefined && item.civicaddress !== undefined
);

const drivers = mergedInput.filter(item =>
  item.home_address !== undefined && !item.knumber && !item.address
);

return [{
  json: {
    destinationId: detectData.destinationId,
    destinationName: detectData.newName,
    oldName: detectData.oldName,
    nameChanged: detectData.nameChanged,
    destAddress: detectData.destAddress,
    destLabel: detectData.destLabel,
    clients: clients,
    drivers: drivers,
    userId: detectData.userId,
    userName: detectData.userName,
    userRole: detectData.userRole
  }
}];
// v1.0.0 - Prepare async branch data

// Collect Task IDs - v1.0.0
const taskItems = $input.all().map(item => item.json);
const branchData = $('Prepare Tasks and Branches - Code').first().json;

const taskMap = {};
taskItems.forEach(task => {
  if (task.task_type && task.id) {
    taskMap[task.task_type] = task.id;
  }
});

return [{
  json: {
    ...branchData,
    taskIds: taskMap
  }
}];
// v1.0.0 - Collect task IDs

// Format Async Response - v1.0.0
const detectData = $('Detect Changes - Code').first().json;
const updatedDest = $('Update Destination - Supabase').first().json;
const input = $input.first().json;

return [{
  json: {
    success: true,
    message: 'Destination updated. Background tasks started for distance recalculation.',
    data: {
      destination: updatedDest,
      addressChanged: detectData.addressChanged === 'true',
      nameChanged: detectData.nameChanged === 'true',
      backgroundTasks: input.taskIds || {}
    },
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Async response with task IDs

// Format Simple Response - v1.0.0
// No async needed — just return the updated destination
const updatedDest = $('Update Destination - Supabase').first().json;
const detectData = $('Detect Changes - Code').first().json;

if (!updatedDest || updatedDest.error || !updatedDest.id) {
  return [{
    json: {
      success: false,
      message: updatedDest?.error ? 'Database error' : 'Destination not found',
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    success: true,
    message: 'Destination updated successfully.',
    data: {
      destination: updatedDest,
      addressChanged: false,
      nameChanged: detectData.nameChanged === 'true',
      backgroundTasks: {}
    },
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Simple response (no async)

// Format Name-Only Response - v1.0.0
// Name changed but address didn't — respond with rename task info
const detectData = $('Detect Changes - Code').first().json;
const updatedDest = $('Update Destination - Supabase').first().json;

return [{
  json: {
    success: true,
    message: 'Destination updated. Renaming travel time keys in background.',
    data: {
      destination: updatedDest,
      addressChanged: false,
      nameChanged: true,
      backgroundTasks: { rename_travel_times: 'inline' }
    },
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Name-only rename response

// Format Error Response - v1.0.0
const errorData = $input.first().json;

return [{
  json: {
    success: false,
    message: errorData.message || 'Validation failed',
    errors: errorData.errors || [],
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Validation error response

// Unauthorized Response - v1.0.0
const data = $input.first().json;

return [{
  json: {
    success: false,
    message: data.message || 'Unauthorized',
    statusCode: data.statusCode || 401,
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Unauthorized error response

// Not Found Response - v1.0.0
return [{
  json: {
    success: false,
    message: 'Destination not found',
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0

// Branch A: Prepare Distance Requests (Batched) - v1.0.0
// Batches up to 25 origins per Maps API call for distance recalc
const data = $input.first().json;
const apiKey = $('Get Maps API Key - Supabase').first().json.value;
const taskId = data.taskIds.recalculate_distances;

if (!apiKey) {
  console.error('Google Maps API key not found');
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: 'Google Maps API key not found'
    }
  }];
}

const destAddr = data.destAddress;
const BATCH_SIZE = 25;
const allReqs = [];

// Client -> destination distances
data.clients.forEach(client => {
  const priAddr = [client.civicaddress, client.city, client.prov, client.postalcode].filter(Boolean).join(', ');
  if (!priAddr) return;

  allReqs.push({
    type: 'client_destination',
    entityId: client.id,
    destinationId: data.destinationId,
    origin: priAddr,
    addressType: 'primary'
  });

  if (client.secondary_civic_address) {
    const secAddr = [client.secondary_civic_address, client.secondary_city, client.secondary_province, client.secondary_postal_code].filter(Boolean).join(', ');
    if (secAddr) {
      allReqs.push({
        type: 'client_destination',
        entityId: client.id,
        destinationId: data.destinationId,
        origin: secAddr,
        addressType: 'secondary'
      });
    }
  }
});

// Driver -> destination distances
data.drivers.forEach(driver => {
  if (!driver.home_address) return;
  allReqs.push({
    type: 'driver_destination',
    entityId: driver.id,
    destinationId: data.destinationId,
    origin: driver.home_address,
    addressType: 'primary'
  });
});

if (allReqs.length === 0) {
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: 'No distances to calculate'
    }
  }];
}

const batches = [];
for (let i = 0; i < allReqs.length; i += BATCH_SIZE) {
  const batch = allReqs.slice(i, i + BATCH_SIZE);
  const origins = batch.map(r => r.origin).join('|');
  batches.push({
    json: {
      origins: origins,
      destinations: destAddr,
      apiKey: apiKey,
      taskId: taskId,
      batchMeta: batch,
      batchIndex: Math.floor(i / BATCH_SIZE)
    }
  });
}

return batches;
// v1.0.0 - Batched distance requests (25 per call)

// Branch A: Process Batch Results - v2.0.0
// v2.0.0: Add hasResults flag for delete-after-success pattern
const results = $input.all();
const origBatches = $('Branch A: Prepare Distances - Code').all();
const taskId = origBatches[0]?.json?.taskId;

if (origBatches[0]?.json?.branchError === 'true') {
  return [{
    json: {
      hasResults: 'false',
      tableType: 'error',
      taskId: taskId,
      errorMessage: origBatches[0].json.errorMessage
    }
  }];
}

const cdMap = {};
const ddMap = {};

results.forEach((result, batchIdx) => {
  const batch = origBatches[batchIdx]?.json;
  if (!batch || !batch.batchMeta) return;
  const meta = batch.batchMeta;
  const rows = result.json.rows || [];

  rows.forEach((row, rowIdx) => {
    const req = meta[rowIdx];
    if (!req) return;
    const el = row.elements?.[0];
    let distKm = null;
    let durMin = null;
    if (el && el.status === 'OK') {
      distKm = parseFloat((el.distance.value / 1000).toFixed(2));
      durMin = Math.ceil(el.duration.value / 60);
    }

    if (req.type === 'client_destination') {
      const k = req.entityId + '_' + req.destinationId;
      if (!cdMap[k]) {
        cdMap[k] = { client_id: req.entityId, destination_id: req.destinationId };
      }
      if (req.addressType === 'primary') {
        cdMap[k].primary_distance_km = distKm;
        cdMap[k].primary_duration_minutes = durMin;
      } else {
        cdMap[k].secondary_distance_km = distKm;
        cdMap[k].secondary_duration_minutes = durMin;
      }
    } else if (req.type === 'driver_destination') {
      const k = req.entityId + '_' + req.destinationId;
      ddMap[k] = {
        driver_id: req.entityId,
        destination_id: req.destinationId,
        distance_km: distKm,
        duration_minutes: durMin
      };
    }
  });
});

const now = new Date().toISOString();
const outputs = [];

Object.values(cdMap).forEach(rec => {
  outputs.push({
    json: {
      hasResults: 'true',
      tableType: 'client_destination',
      taskId: taskId,
      client_id: rec.client_id,
      destination_id: rec.destination_id,
      primary_distance_km: rec.primary_distance_km,
      primary_duration_minutes: rec.primary_duration_minutes,
      secondary_distance_km: rec.secondary_distance_km || null,
      secondary_duration_minutes: rec.secondary_duration_minutes || null,
      calculated_at: now,
      calculation_source: 'google_maps'
    }
  });
});

Object.values(ddMap).forEach(rec => {
  outputs.push({
    json: {
      hasResults: 'true',
      tableType: 'driver_destination',
      taskId: taskId,
      driver_id: rec.driver_id,
      destination_id: rec.destination_id,
      distance_km: rec.distance_km,
      duration_minutes: rec.duration_minutes,
      calculated_at: now,
      calculation_source: 'google_maps'
    }
  });
});

if (outputs.length === 0) {
  return [{ json: { hasResults: 'false', tableType: 'none', taskId: taskId } }];
}

return outputs;
// v2.0.0 - Add hasResults flag, delete-after-success

// Restore Distance Data - v1.0.0
// Delete nodes lose input; re-read from Process Results
return $('Branch A: Process Results - Code').all();
// v1.0.0 - Restore data after delete

// Branch A: Mark Task Status - v2.0.0
// v2.0.0: Handle no-results path from Has Results Switch
const allResults = $input.all();
const prepNode = $('Branch A: Prepare Distances - Code').first().json;
const taskId = prepNode.taskId;
const firstInput = allResults[0]?.json || {};

// Error path
if (prepNode.branchError === 'true' || firstInput.tableType === 'error') {
  const errMsg = firstInput.errorMessage || prepNode.errorMessage || 'Unknown error';
  return [{
    json: {
      taskId: taskId,
      status: 'failed',
      error_message: errMsg,
      completed_at: new Date().toISOString(),
      result: JSON.stringify({ error: errMsg }),
      branch: 'A'
    }
  }];
}

// No results path
if (firstInput.hasResults === 'false' || firstInput.tableType === 'none') {
  return [{
    json: {
      taskId: taskId,
      status: 'completed',
      error_message: null,
      completed_at: new Date().toISOString(),
      result: JSON.stringify({ distances_inserted: 0, note: 'No results from Maps API' }),
      branch: 'A'
    }
  }];
}

// Success path
return [{
  json: {
    taskId: taskId,
    status: 'completed',
    error_message: null,
    completed_at: new Date().toISOString(),
    result: JSON.stringify({ distances_inserted: allResults.length }),
    branch: 'A'
  }
}];
// v2.0.0 - Handle no-results + error paths

// Branch B: Prepare Travel Time Requests (Batched) - v1.0.0
// Batches up to 25 client addresses per Maps API call
const data = $input.first().json;
const apiKey = $('Get Maps API Key - Supabase').first().json.value;
const taskId = data.taskIds.recalculate_travel_times;

if (!apiKey) {
  console.error('Google Maps API key not found');
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: 'Google Maps API key not found'
    }
  }];
}

const destAddr = data.destAddress;
const destName = data.destinationName;
const destId = data.destinationId;
const BATCH_SIZE = 25;
const allReqs = [];

data.clients.forEach(client => {
  const priAddr = [client.civicaddress, client.city, client.prov, client.postalcode].filter(Boolean).join(', ');
  if (!priAddr) return;

  allReqs.push({
    clientId: client.id,
    knumber: client.knumber,
    clientAddress: priAddr,
    addressType: 'primary'
  });

  if (client.secondary_civic_address) {
    const secAddr = [client.secondary_civic_address, client.secondary_city, client.secondary_province, client.secondary_postal_code].filter(Boolean).join(', ');
    if (secAddr) {
      allReqs.push({
        clientId: client.id,
        knumber: client.knumber,
        clientAddress: secAddr,
        addressType: 'secondary'
      });
    }
  }
});

if (allReqs.length === 0) {
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: 'No clients for travel times'
    }
  }];
}

const batches = [];
for (let i = 0; i < allReqs.length; i += BATCH_SIZE) {
  const batch = allReqs.slice(i, i + BATCH_SIZE);
  const origins = batch.map(r => r.clientAddress).join('|');
  batches.push({
    json: {
      origins: origins,
      destinations: destAddr,
      apiKey: apiKey,
      taskId: taskId,
      destinationName: destName,
      destinationId: destId,
      batchMeta: batch,
      batchIndex: Math.floor(i / BATCH_SIZE)
    }
  });
}

return batches;
// v1.0.0 - Batched travel time requests

// Branch B: Aggregate Travel Times - v1.0.0
const mapsResults = $input.all();
const origBatches = $('Branch B: Prepare Requests - Code').all();
const taskId = origBatches[0]?.json?.taskId;
const destName = origBatches[0]?.json?.destinationName;

if (origBatches[0]?.json?.branchError === 'true') {
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: origBatches[0].json.errorMessage
    }
  }];
}

const clientTravelTimes = {};
let successCount = 0;
let failCount = 0;

mapsResults.forEach((result, batchIdx) => {
  const batch = origBatches[batchIdx]?.json;
  if (!batch || !batch.batchMeta) return;
  const meta = batch.batchMeta;
  const rows = result.json.rows || [];

  rows.forEach((row, rowIdx) => {
    const req = meta[rowIdx];
    if (!req) return;
    const el = row.elements?.[0];
    const cid = req.clientId;
    const addr = req.addressType;

    if (!clientTravelTimes[cid]) {
      clientTravelTimes[cid] = { clientId: cid };
    }

    if (el && el.status === 'OK') {
      const rawMin = Math.ceil(el.duration.value / 60);
      const durMin = Math.ceil((rawMin + 5) / 5) * 5;
      const distKm = parseFloat((el.distance.value / 1000).toFixed(2));
      clientTravelTimes[cid][addr] = {
        duration_minutes: durMin,
        distance_km: distKm,
        calculated_at: new Date().toISOString()
      };
      successCount++;
    } else {
      clientTravelTimes[cid][addr] = {
        duration_minutes: null,
        distance_km: null,
        calculated_at: new Date().toISOString(),
        error: 'Maps API failed'
      };
      failCount++;
    }
  });
});

if (failCount > 0) {
  console.error('Branch B: ' + failCount + ' travel time calcs failed');
}

const outputs = Object.values(clientTravelTimes).map(ct => ({
  json: {
    clientId: ct.clientId,
    destName: destName,
    travelData: ct,
    taskId: taskId
  }
}));

if (outputs.length === 0) {
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: 'No travel times calculated'
    }
  }];
}

outputs[0].json.successCount = successCount;
outputs[0].json.failCount = failCount;

return outputs;
