// Branch B: Merge Travel Times - v2.0.0
// v2.0.0: Handle name rename — remove old key, add new key
const prepData = $('Branch B: Prepare Merge - Code').first().json;
const client = $input.first().json;
const destName = prepData.destName;
const oldName = prepData.oldName;
const nameChanged = prepData.nameChanged === 'true';
const newEntry = prepData.newTravelEntry;

let travelTimes = client.clinic_travel_times || {};
if (typeof travelTimes === 'string') {
  try { travelTimes = JSON.parse(travelTimes); }
  catch(e) { travelTimes = {}; }
}

// If name changed and old key exists, remove it
if (nameChanged && oldName && oldName !== destName && travelTimes[oldName]) {
  delete travelTimes[oldName];
}

// Write new travel times under the (possibly new) name
travelTimes[destName] = {
  ...(travelTimes[destName] || {}),
  ...newEntry
};

return [{
  json: {
    clientId: prepData.clientId,
    mergedTravelTimes: travelTimes,
    taskId: prepData.taskId,
