// Update Driver Clinic Preferences - v1.0.0
// Merge recalculated destination distances into driver clinic_preferences
const branchData = $('Prepare Tasks and Branches - Code').first().json;
const destId = String(branchData.destinationId);
const drivers = branchData.drivers;

const ddResults = $('Branch A: Process Results - Code').all().filter(item => item.json.tableType === 'driver_destination');

const ddMap = {};
ddResults.forEach(item => {
  const d = item.json;
  ddMap[String(d.driver_id)] = {
    distance_km: d.distance_km,
    duration_minutes: d.duration_minutes
  };
});

const outputs = [];

drivers.forEach(driver => {
  let prefs = driver.clinic_preferences || {};
  if (typeof prefs === 'string') {
    try { prefs = JSON.parse(prefs); } catch(e) { prefs = {}; }
  }

  // Only update drivers that have explicit preferences
  if (Object.keys(prefs).length === 0) return;

  // Only update if this destination already exists in their prefs
  // (for update workflow, don't add new entries — only recalculate existing)
  if (!prefs[destId]) return;

  const dd = ddMap[String(driver.id)] || {};
  prefs[destId] = {
    ...prefs[destId],
    distance_km: dd.distance_km || null,
    drive_time_min: dd.duration_minutes || null
  };

  outputs.push({
    json: {
      driverId: driver.id,
      clinic_preferences: prefs
    }
  });
});

if (outputs.length === 0) {
  return [{
    json: {
      skipDriverUpdate: 'true',
      message: 'No drivers need preference updates'
    }
  }];
}

return outputs;
