// Branch C: Rename JSONB Keys - v1.0.0
// Iterates all clients, renames oldName key to newName in clinic_travel_times
const renameData = $('Branch C: Prepare Rename - Code').first().json;
const oldName = renameData.oldName;
const newName = renameData.newName;
const clients = $input.all().map(item => item.json);

const outputs = [];
let renameCount = 0;

clients.forEach(client => {
  let tt = client.clinic_travel_times || {};
  if (typeof tt === 'string') {
    try { tt = JSON.parse(tt); } catch(e) { tt = {}; }
  }

  // Only rename if this client has the old key
  if (!tt[oldName]) return;

  // Copy old key data to new key, preserving any existing new key data
  tt[newName] = { ...(tt[newName] || {}), ...tt[oldName] };
  delete tt[oldName];

  outputs.push({
    json: {
      clientId: client.id,
      mergedTravelTimes: tt
    }
  });
  renameCount++;
});

if (outputs.length === 0) {
  return [{
    json: {
      skipRename: 'true',
      message: 'No clients had travel times for old name',
      renameCount: 0
    }
  }];
}

// Add rename count to first item
outputs[0].json.renameCount = renameCount;

return outputs;
